queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?coursename ?teachername WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCourses ?child ; p:hasStudents ?parent . } GROUP BY ?child }
  ?child p:CourseName ?coursename .
  ?child p:TeacherName ?teachername .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Students } }
  FILTER(?nf = ?total)
}

