ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?fullname ?coursename WHERE {
  ?enrollments a :Enrollments .
  ?courses a :Courses .
  ?enrollments p:hasCourses ?courses .
  ?students a :Students .
  ?enrollments p:hasStudents ?students .
  ?students p:name ?fullname .
  ?courses p:CourseName ?coursename .
} }
  collective: { SELECT ?coursename WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCourses ?child ; p:hasStudents ?parent . } GROUP BY ?child }
  ?child p:CourseName ?coursename .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Students } }
  FILTER(?nf = ?total)
} }
}

